  1→import { useRef, useCallback, useEffect, useState } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { useEditorTool } from '@/editor/useEditorTool';
  5→import { MIN_ZOOM, MAX_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
  6→import { TOOLS } from '@/editor/tools';
  7→import GridRenderer from './GridRenderer';
  8→import SlabRenderer from './SlabRenderer';
  9→import WallRenderer from './WallRenderer';
 10→import BeamRenderer from './BeamRenderer';
 11→import StairRenderer from './StairRenderer';
 12→import DoorRenderer from './DoorRenderer';
 13→import WindowRenderer from './WindowRenderer';
 14→import RoomRenderer from './RoomRenderer';
 15→import AnnotationRenderer from './AnnotationRenderer';
 16→import ElevationRenderer from './ElevationRenderer';
 17→import SectionRenderer from './SectionRenderer';
 18→import SelectionOverlay from './SelectionOverlay';
 19→import DimensionPreview from './DimensionPreview';
 20→import WallPreview from './WallPreview';
 21→import ColumnRenderer from './ColumnRenderer';
 22→import ColumnPreview from './ColumnPreview';
 23→import BeamPreview from './BeamPreview';
 24→import StairPreview from './StairPreview';
 25→import SlabPreview from './SlabPreview';
 26→import DoorWindowPreview from './DoorWindowPreview';
 27→import RoomPreview from './RoomPreview';
 28→import SectionCutRenderer from './SectionCutRenderer';
 29→import SectionCutPreview from './SectionCutPreview';
 30→import { isTypingTarget } from '@/utils/keyboard';
 31→import styles from './SvgCanvas.module.css';
 32→
 33→function screenToModel(screenX, screenY, viewport, svgRect) {
 34→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 35→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 36→  return { x, y };
 37→}
 38→
 39→export default function SvgCanvas() {
 40→  const svgRef = useRef(null);
 41→  const isPanning = useRef(false);
 42→  const lastPanPos = useRef({ x: 0, y: 0 });
 43→  const spaceHeld = useRef(false);
 44→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 45→
 46→  const { project, dispatch, getFloor } = useProject();
 47→  const editor = useEditor();
 48→  const {
 49→    activeTool, selectedId, selectedType, toolState,
 50→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode,
 51→    dispatch: editorDispatch,
 52→  } = editor;
 53→
 54→  const floor = getFloor(activeFloorId);
 55→
 56→  const tool = useEditorTool({
 57→    activeTool,
 58→    dispatch,
 59→    editorDispatch,
 60→    getFloor,
 61→    activeFloorId,
 62→    viewport,
 63→    snapEnabled,
 64→    selectedId,
 65→    selectedType,
 66→    toolState,
 67→    viewMode,
 68→  });
 69→
 70→  const getModelPos = useCallback((e) => {
 71→    const rect = svgRef.current.getBoundingClientRect();
 72→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 73→  }, [viewport]);
 74→
 75→  const handleMouseDown = useCallback((e) => {
 76→    // Middle mouse or space+left for pan
 77→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 78→      isPanning.current = true;
 79→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 80→      e.preventDefault();
 81→      return;
 82→    }
 83→
 84→    const modelPos = getModelPos(e);
 85→    tool.onMouseDown(modelPos, e);
 86→  }, [getModelPos, tool]);
 87→
 88→  const handleMouseMove = useCallback((e) => {
 89→    if (isPanning.current) {
 90→      const dx = e.clientX - lastPanPos.current.x;
 91→      const dy = e.clientY - lastPanPos.current.y;
 92→      editorDispatch({ type: 'PAN', dx, dy });
 93→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 94→      return;
 95→    }
 96→
 97→    const modelPos = getModelPos(e);
 98→    setCursorPos(modelPos);
 99→    tool.onMouseMove(modelPos, e);
100→  }, [getModelPos, tool, editorDispatch]);
101→
102→  const handleMouseUp = useCallback((e) => {
103→    if (isPanning.current) {
104→      isPanning.current = false;
105→      return;
106→    }
107→    const modelPos = getModelPos(e);
108→    tool.onMouseUp(modelPos, e);
109→  }, [getModelPos, tool]);
110→
111→  const handleDoubleClick = useCallback((e) => {
112→    const modelPos = getModelPos(e);
113→    tool.onDoubleClick(modelPos, e);
114→  }, [getModelPos, tool]);
115→
116→  const handleWheel = useCallback((e) => {
117→    e.preventDefault();
118→    const rect = svgRef.current.getBoundingClientRect();
119→    const mouseX = e.clientX - rect.left;
120→    const mouseY = e.clientY - rect.top;
121→
122→    const direction = e.deltaY < 0 ? 1 : -1;
123→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
124→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
125→
126→    // Zoom centered on cursor
127→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
128→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
129→
130→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
131→  }, [viewport, editorDispatch]);
132→
133→  useEffect(() => {
134→    if (!statusMessage) return undefined;
135→
136→    const timer = window.setTimeout(() => {
137→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
138→    }, 2500);
139→
140→    return () => window.clearTimeout(timer);
141→  }, [statusMessage, editorDispatch]);
142→
143→  useEffect(() => {
144→    const handleKeyDown = (e) => {
145→      if (isTypingTarget(e.target)) return;
146→
147→      if (e.key === ' ') {
148→        spaceHeld.current = true;
149→        e.preventDefault();
150→      }
151→
152→      // Tool shortcuts
153→      if (viewMode === 'plan' && !e.ctrlKey && !e.metaKey) {
154→        switch (e.key.toLowerCase()) {
155→          case 'v':
156→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
157→            return;
158→          case 'm':
159→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
160→            return;
161→          case 'w':
162→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
163→            return;
164→          case 'b':
165→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
166→            return;
167→          case 't':
168→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
169→            return;
170→          case 'q':
171→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
172→            return;
173→          case 's':
174→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
175→            return;
176→          case 'r':
177→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
178→            return;
179→          case 'd':
180→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
181→            return;
182→          case 'n':
183→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
184→            return;
185→          case 'c':
186→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
187→            return;
188→        }
189→      }
190→
191→      tool.onKeyDown(e);
192→    };
193→
194→    const handleKeyUp = (e) => {
195→      if (isTypingTarget(e.target)) return;
196→
197→      if (e.key === ' ') {
198→        spaceHeld.current = false;
199→      }
200→    };
201→
202→    window.addEventListener('keydown', handleKeyDown);
203→    window.addEventListener('keyup', handleKeyUp);
204→    return () => {
205→      window.removeEventListener('keydown', handleKeyDown);
206→      window.removeEventListener('keyup', handleKeyUp);
207→    };
208→  }, [tool, editorDispatch, viewMode]);
209→
210→  // Prevent default context menu on SVG
211→  useEffect(() => {
212→    const svg = svgRef.current;
213→    if (!svg) return;
214→    const prevent = (e) => e.preventDefault();
215→    svg.addEventListener('contextmenu', prevent);
216→    svg.addEventListener('wheel', handleWheel, { passive: false });
217→    return () => {
218→      svg.removeEventListener('contextmenu', prevent);
219→      svg.removeEventListener('wheel', handleWheel);
220→    };
221→  }, [handleWheel]);
222→
223→  const cursor = spaceHeld.current ? 'grab' : tool.getCursor();
224→  const zoomPercent = Math.round(viewport.zoom * 1000);
225→
226→  return (
227→    <div className={styles.canvasContainer}>
228→      <svg
229→        ref={svgRef}
230→        className={styles.svg}
231→        style={{ cursor }}
232→        onMouseDown={handleMouseDown}
233→        onMouseMove={handleMouseMove}
234→        onMouseUp={handleMouseUp}
235→        onDoubleClick={handleDoubleClick}
236→      >
237→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
238→          {viewMode === 'plan' && showGrid && <GridRenderer />}
239→          {viewMode === 'plan' && showGrid && (
240→            <rect
241→              x={-100000} y={-100000}
242→              width={200000} height={200000}
243→              fill="url(#grid-major)"
244→              style={{ pointerEvents: 'none' }}
245→            />
246→          )}
247→          {floor && (
248→            viewMode === 'plan' ? (
249→              <>
250→                <SlabRenderer slab={floor.slab} selectedId={selectedId} />
251→                <RoomRenderer rooms={floor.rooms} selectedId={selectedId} />
252→                <RoomPreview toolState={toolState} activeTool={activeTool} />
253→                <WallRenderer walls={floor.walls} columns={floor.columns || []} />
254→                <BeamRenderer beams={floor.beams || []} columns={floor.columns || []} />
255→                <StairRenderer stairs={floor.stairs || []} />
256→                <ColumnRenderer columns={floor.columns || []} />
257→                <DoorRenderer doors={floor.doors} walls={floor.walls} />
258→                <WindowRenderer windows={floor.windows} walls={floor.walls} />
259→                <SectionCutRenderer sectionCut={floor.sectionCut} selectedId={selectedId} />
260→                <AnnotationRenderer floor={floor} />
261→                <SelectionOverlay
262→                  selectedId={selectedId}
263→                  selectedType={selectedType}
264→                  floor={floor}
265→                  zoom={viewport.zoom}
266→                />
267→                <DimensionPreview toolState={toolState} activeTool={activeTool} />
268→                <WallPreview toolState={toolState} activeTool={activeTool} />
269→                <SlabPreview toolState={toolState} activeTool={activeTool} />
270→                <BeamPreview
271→                  toolState={toolState}
272→                  activeTool={activeTool}
273→                  columns={floor.columns || []}
274→                  floorLevel={floor.level}
275→                />
276→                <StairPreview
277→                  toolState={toolState}
278→                  activeTool={activeTool}
279→                  floorId={floor.id}
280→                />
281→                <DoorWindowPreview
282→                  toolState={toolState}
283→                  activeTool={activeTool}
284→                  walls={floor.walls}
285→                />
286→                <SectionCutPreview toolState={toolState} activeTool={activeTool} />
287→                <ColumnPreview toolState={toolState} activeTool={activeTool} />
288→              </>
289→            ) : viewMode === 'section_view' ? (
290→              <SectionRenderer floor={floor} />
291→            ) : (
292→              <ElevationRenderer floor={floor} viewMode={viewMode} />
293→            )
294→          )}
295→        </g>
296→      </svg>
297→      <div className={styles.statusBar}>
298→        <span>X: {Math.round(cursorPos.x)} mm</span>
299→        <span>Y: {Math.round(cursorPos.y)} mm</span>
300→        <span>Zoom: {zoomPercent}%</span>
301→        <span>View: {viewMode}</span>
302→        <span>Tool: {activeTool}</span>
303→        {statusMessage && <span className={styles.statusMessage}>{statusMessage}</span>}
304→      </div>
305→    </div>
306→  );
307→}
