 1→import { GRID_MINOR, GRID_MAJOR } from '@/domain/defaults';
 2→
 3→export default function GridRenderer() {
 4→  return (
 5→    <defs>
 6→      <pattern
 7→        id="grid-minor"
 8→        width={GRID_MINOR}
 9→        height={GRID_MINOR}
10→        patternUnits="userSpaceOnUse"
11→      >
12→        <path
13→          d={`M ${GRID_MINOR} 0 L 0 0 0 ${GRID_MINOR}`}
14→          fill="none"
15→          stroke="var(--color-grid-minor)"
16→          strokeWidth={1}
17→          vectorEffect="non-scaling-stroke"
18→        />
19→      </pattern>
20→      <pattern
21→        id="grid-major"
22→        width={GRID_MAJOR}
23→        height={GRID_MAJOR}
24→        patternUnits="userSpaceOnUse"
25→      >
26→        <rect width={GRID_MAJOR} height={GRID_MAJOR} fill="url(#grid-minor)" />
27→        <path
28→          d={`M ${GRID_MAJOR} 0 L 0 0 0 ${GRID_MAJOR}`}
29→          fill="none"
30→          stroke="var(--color-grid-major)"
31→          strokeWidth={2}
32→          vectorEffect="non-scaling-stroke"
33→        />
34→      </pattern>
35→    </defs>
36→  );
37→}
38→

 1→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
 2→
 3→export default function WallRenderer({ walls, columns }) {
 4→  return (
 5→    <g className="walls">
 6→      {walls.map(wall => {
 7→        const outline = getWallRenderData(wall, columns || []).outline;
 8→        const points = outline.map(p => `${p.x},${p.y}`).join(' ');
 9→        return (
10→          <polygon
11→            key={wall.id}
12→            data-id={wall.id}
13→            data-type="wall"
14→            points={points}
15→            fill="var(--color-wall-fill)"
16→            stroke="var(--color-wall-stroke)"
17→            strokeWidth={1}
18→            vectorEffect="non-scaling-stroke"
19→          />
20→        );
21→      })}
22→    </g>
23→  );
24→}
25→

 1→export default function RoomRenderer({ rooms, selectedId }) {
 2→  return (
 3→    <g className="rooms">
 4→      {rooms.map(room => {
 5→        const hasPolygon = room.points?.length >= 3;
 6→        const isSelected = room.id === selectedId;
 7→
 8→        return (
 9→          <g key={room.id} data-id={room.id} data-type="room">
10→            {hasPolygon && (
11→              <polygon
12→                points={room.points.map(p => `${p.x},${p.y}`).join(' ')}
13→                fill={room.color}
14→                fillOpacity={isSelected ? 0.55 : 0.4}
15→                stroke="none"
16→                style={{ pointerEvents: 'all', cursor: 'pointer' }}
17→              />
18→            )}
19→          </g>
20→        );
21→      })}
22→    </g>
23→  );
24→}
