 28→function DoubleDoor({ door, info }) {
 29→  const angleDeg = (info.angle * 180) / Math.PI;
 30→  const halfWidth = door.width / 2;
 31→
 32→  return (
 33→    <g transform={`translate(${info.center.x},${info.center.y}) rotate(${angleDeg})`}>
 34→      {/* Left leaf */}
