  1→import { windowOutlineOnWall, wallDirection } from '@/geometry/wallGeometry';
  2→import { perpendicular, scale, add } from '@/geometry/point';
  3→
  4→function StandardWindow({ info, wall }) {
  5→  const dir = wallDirection(wall);
  6→  const perp = perpendicular(dir);
  7→  const halfThick = wall.thickness / 2;
  8→
  9→  const lines = [-0.3, 0, 0.3].map(fraction => {
 10→    const offset = scale(perp, halfThick * fraction);
 11→    return {
 12→      x1: add(info.start, offset).x,
 13→      y1: add(info.start, offset).y,
 14→      x2: add(info.end, offset).x,
 15→      y2: add(info.end, offset).y,
 16→    };
 17→  });
 18→
 19→  return lines.map((l, i) => (
 20→    <line
 21→      key={i}
 22→      x1={l.x1} y1={l.y1}
 23→      x2={l.x2} y2={l.y2}
 24→      stroke="var(--color-wall-fill)"
 25→      strokeWidth={i === 1 ? 2 : 1}
 26→      vectorEffect="non-scaling-stroke"
 27→    />
 28→  ));
 29→}
 30→
 31→function CasementWindow({ win, info }) {
 32→  const angleDeg = (info.angle * 180) / Math.PI;
 33→  const flipSign = win.openDirection === 'right' ? -1 : 1;
 34→  const leafLen = win.width * 0.3;
 35→
 36→  return (
 37→    <g transform={`translate(${info.start.x},${info.start.y}) rotate(${angleDeg})`}>
 38→      {/* Glass pane line */}
 39→      <line
 40→        x1={0} y1={0}
 41→        x2={win.width} y2={0}
 42→        stroke="var(--color-wall-fill)"
 43→        strokeWidth={2}
 44→        vectorEffect="non-scaling-stroke"
 45→      />
 46→      {/* Hinge leaf */}
 47→      <line
 48→        x1={0} y1={0}
 49→        x2={0} y2={flipSign * -leafLen}
 50→        stroke="var(--color-wall-fill)"
 51→        strokeWidth={1}
 52→        vectorEffect="non-scaling-stroke"
 53→      />
 54→      {/* Quarter-circle arc */}
 55→      <path
 56→        d={`M ${leafLen} 0 A ${leafLen} ${leafLen} 0 0 ${win.openDirection === 'left' ? 1 : 0} 0 ${flipSign * -leafLen}`}
 57→        fill="none"
 58→        stroke="var(--color-wall-fill)"
 59→        strokeWidth={1}
 60→        strokeDasharray="4 3"
 61→        vectorEffect="non-scaling-stroke"
 62→      />
 63→    </g>
 64→  );
 65→}
