 95→export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
 96→  return {
 97→    onMouseDown(modelPos, e, toolState) {
 98→      if (e.button !== 0) return;
 99→
100→      const floor = getFloor(activeFloorId);
101→      if (!floor) return;
102→
103→      // Check if clicking a handle
104→      const target = e.target;
105→      if (target.dataset.handle) {
106→        editorDispatch({
107→          type: 'UPDATE_TOOL_STATE',
108→          payload: {
109→            dragging: true,
110→            dragType: 'handle',
111→            handle: target.dataset.handle,
112→            handleIndex: target.dataset.index != null ? Number(target.dataset.index) : null,
113→            startPos: modelPos,
114→          },
115→        });
116→        return;
117→      }
118→
119→      const hit = hitTest(modelPos, floor, SNAP_DISTANCE_PX / viewport.zoom * 2.5);
120→      if (hit) {
121→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
122→        const draggableTypes = new Set(['wall', 'column', 'door', 'window', 'stair', 'sectionCut']);
123→        if (!draggableTypes.has(hit.type)) return;
124→        editorDispatch({
125→          type: 'UPDATE_TOOL_STATE',
126→          payload: {
127→            dragging: true,
128→            dragType: 'move',
129→            startPos: modelPos,
130→            originalPos: modelPos,
131→          },
132→        });
133→      } else {
134→        editorDispatch({ type: 'DESELECT' });
135→      }
136→    },
137→
138→    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
139→      if (!toolState.dragging || !selectedId) return;
140→
141→      const floor = getFloor(activeFloorId);
142→      if (!floor) return;
143→      const dx = modelPos.x - toolState.startPos.x;
144→      const dy = modelPos.y - toolState.startPos.y;
145→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
146→
147→      if (selectedType === 'wall') {
148→        const wall = floor.walls.find(w => w.id === selectedId);
149→        if (!wall) return;
150→        const resolved = resolveWallEndpoints(wall, floor.columns || []);
151→
152→        if (toolState.dragType === 'handle') {
153→          const handle = toolState.handle;
154→          const oppositeKey = handle === 'start' ? 'end' : 'start';
155→          const oppositePoint = resolved[oppositeKey];
156→          let nextPoint = modelPos;
157→          let nextAttachment = null;
158→
159→          if (e.shiftKey) {
160→            const dx = modelPos.x - oppositePoint.x;
161→            const dy = modelPos.y - oppositePoint.y;
162→            const angle = Math.atan2(dy, dx);
163→            const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
164→            const len = Math.sqrt(dx * dx + dy * dy);
165→            nextPoint = {
166→              x: oppositePoint.x + Math.cos(snapAngle) * len,
167→              y: oppositePoint.y + Math.sin(snapAngle) * len,
168→            };
169→          } else if (snapEnabled) {
170→            const snapResult = snapWallEndpoint(modelPos, {
171→              walls: floor.walls,
172→              columns: floor.columns || [],
173→              snapDist: snapDistModel,
174→              otherPoint: oppositePoint,
175→              ignoreWallId: wall.id,
176→            });
177→            if (snapResult) {
178→              nextPoint = snapResult.point;
179→              nextAttachment = snapResult.attachment;
180→            }
181→          }
182→
183→          if (distance(nextPoint, oppositePoint) < MIN_WALL_LENGTH) return;
184→
185→          dispatch({
186→            type: 'WALL_UPDATE',
187→            floorId: activeFloorId,
188→            wall: {
189→              id: wall.id,
190→              [handle]: nextPoint,
191→              [`${handle}Attachment`]: nextAttachment,
192→            },
193→          });
194→        } else {
195→          let nextStart = { x: resolved.start.x + dx, y: resolved.start.y + dy };
196→          let nextEnd = { x: resolved.end.x + dx, y: resolved.end.y + dy };
197→          let startAttachment = null;
198→          let endAttachment = null;
199→
200→          if (snapEnabled) {
201→            const startSnap = snapWallEndpoint(nextStart, {
202→              walls: floor.walls,
203→              columns: floor.columns || [],
204→              snapDist: snapDistModel,
205→              otherPoint: nextEnd,
206→              ignoreWallId: wall.id,
207→            });
208→            if (startSnap) {
209→              nextStart = startSnap.point;
210→              startAttachment = startSnap.attachment;
211→            }
212→
213→            const endSnap = snapWallEndpoint(nextEnd, {
214→              walls: floor.walls,
215→              columns: floor.columns || [],
216→              snapDist: snapDistModel,
217→              otherPoint: nextStart,
218→              ignoreWallId: wall.id,
219→            });
220→            if (endSnap) {
221→              nextEnd = endSnap.point;
222→              endAttachment = endSnap.attachment;
223→            }
224→          }
225→
226→          if (distance(nextStart, nextEnd) < MIN_WALL_LENGTH) return;
227→
228→          dispatch({
229→            type: 'WALL_UPDATE',
230→            floorId: activeFloorId,
231→            wall: {
232→              id: wall.id,
233→              start: nextStart,
234→              end: nextEnd,
235→              startAttachment,
236→              endAttachment,
237→            },
238→          });
239→        }
240→        editorDispatch({
241→          type: 'UPDATE_TOOL_STATE',
242→          payload: { startPos: modelPos },
243→        });
244→      } else if (selectedType === 'column') {
245→        const col = (floor.columns || []).find(c => c.id === selectedId);
246→        if (!col) return;
247→        dispatch({
248→          type: 'COLUMN_UPDATE',
249→          floorId: activeFloorId,
250→          column: { id: col.id, x: col.x + dx, y: col.y + dy },
251→        });
252→        editorDispatch({
253→          type: 'UPDATE_TOOL_STATE',
254→          payload: { startPos: modelPos },
255→        });
256→      } else if (selectedType === 'sectionCut') {
257→        const sectionCut = floor.sectionCut?.id === selectedId ? floor.sectionCut : null;
258→        if (!sectionCut) return;
259→
260→        if (toolState.dragType === 'handle') {
261→          const handle = toolState.handle;
262→          const nextSectionCut = handle === 'start'
263→            ? { ...sectionCut, startPoint: modelPos }
264→            : { ...sectionCut, endPoint: modelPos };
265→
266→          if (distance(nextSectionCut.startPoint, nextSectionCut.endPoint) < MIN_WALL_LENGTH) return;
267→
268→          dispatch({
269→            type: 'SECTION_UPDATE',
270→            floorId: activeFloorId,
271→            sectionCut: nextSectionCut,
272→          });
273→        } else {
274→          dispatch({
275→            type: 'SECTION_UPDATE',
276→            floorId: activeFloorId,
277→            sectionCut: {
278→              id: sectionCut.id,
279→              startPoint: {
280→                x: sectionCut.startPoint.x + dx,
281→                y: sectionCut.startPoint.y + dy,
282→              },
283→              endPoint: {
284→                x: sectionCut.endPoint.x + dx,
285→                y: sectionCut.endPoint.y + dy,
286→              },
287→            },
288→          });
289→          editorDispatch({
290→            type: 'UPDATE_TOOL_STATE',
291→            payload: { startPos: modelPos },
292→          });
293→        }
294→      } else if (selectedType === 'beam') {
295→        return;
296→      } else if (selectedType === 'stair') {
297→        const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
298→        if (!stair) return;
299→        dispatch({
300→          type: 'STAIR_UPDATE',
301→          floorId: activeFloorId,
302→          stair: {
303→            id: stair.id,
304→            startPoint: {
305→              x: stair.startPoint.x + dx,
306→              y: stair.startPoint.y + dy,
307→            },
308→          },
309→        });
310→        editorDispatch({
311→          type: 'UPDATE_TOOL_STATE',
312→          payload: { startPos: modelPos },
313→        });
314→      } else if (selectedType === 'slab') {
315→        if (toolState.dragType !== 'handle' || toolState.handle !== 'slab-vertex' || toolState.handleIndex == null) {
316→          return;
317→        }
318→        if (!floor.slab || floor.slab.id !== selectedId) return;
319→
320→        const boundaryPoints = floor.slab.boundaryPoints.map((point, index) => (
321→          index === toolState.handleIndex ? { x: modelPos.x, y: modelPos.y } : point
322→        ));
323→
324→        dispatch({
325→          type: 'SLAB_UPDATE',
326→          floorId: activeFloorId,
327→          slab: {
328→            id: floor.slab.id,
329→            boundaryPoints,
330→          },
331→        });
332→        editorDispatch({
333→          type: 'UPDATE_TOOL_STATE',
334→          payload: { startPos: modelPos },
335→        });
336→      } else if (selectedType === 'door' || selectedType === 'window') {
337→        // Slide along parent wall
338→        const items = selectedType === 'door' ? floor.doors : floor.windows;
339→        const item = items.find(i => i.id === selectedId);
340→        if (!item) return;
341→
342→        const wall = floor.walls.find(w => w.id === item.wallId);
343→        if (!wall) return;
344→
345→        const newOffset = projectPointOnWall(wall, modelPos);
346→        const halfWidth = item.width / 2;
347→        const maxOffset = wallLength(wall) - halfWidth;
348→        const clampedOffset = Math.max(halfWidth, Math.min(maxOffset, newOffset));
349→
350→        const updateType = selectedType === 'door' ? 'DOOR_UPDATE' : 'WINDOW_UPDATE';
351→        dispatch({
352→          type: updateType,
353→          floorId: activeFloorId,
354→          [selectedType]: { id: item.id, offset: clampedOffset },
355→        });
356→
357→        editorDispatch({
358→          type: 'UPDATE_TOOL_STATE',
359→          payload: { startPos: modelPos },
360→        });
361→      }
362→    },
363→
364→    onMouseUp(modelPos, e, toolState) {
365→      if (toolState.dragging) {
366→        editorDispatch({
367→          type: 'UPDATE_TOOL_STATE',
368→          payload: { dragging: false, dragType: null, handle: null, handleIndex: null },
369→        });
370→      }
371→    },
372→
373→    onKeyDown(e, toolState, selectedId, selectedType) {
374→      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'd' && selectedId && selectedType === 'column') {
375→        e.preventDefault();
376→        const floor = getFloor(activeFloorId);
377→        if (!floor) return;
378→        const column = (floor.columns || []).find(c => c.id === selectedId);
379→        if (!column) return;
380→        const duplicate = duplicateColumn(column);
381→        dispatch({ type: 'COLUMN_DUPLICATE', floorId: activeFloorId, column: duplicate });
382→        editorDispatch({ type: 'SELECT_OBJECT', id: duplicate.id, objectType: 'column' });
383→        return;
384→      }
385→
386→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
387→        const floor = getFloor(activeFloorId);
388→        if (!floor) return;
389→        if (selectedType === 'wall') {
390→          dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
391→        } else if (selectedType === 'door') {
392→          dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
393→        } else if (selectedType === 'window') {
394→          dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
395→        } else if (selectedType === 'column') {
396→          dispatch({ type: 'COLUMN_DELETE', floorId: activeFloorId, columnId: selectedId });
397→        } else if (selectedType === 'beam') {
398→          dispatch({ type: 'BEAM_DELETE', floorId: activeFloorId, beamId: selectedId });
399→        } else if (selectedType === 'stair') {
400→          dispatch({ type: 'STAIR_DELETE', floorId: activeFloorId, stairId: selectedId });
401→        } else if (selectedType === 'annotation') {
402→          dispatch({ type: 'ANNOTATION_DELETE', floorId: activeFloorId, annotationId: selectedId });
403→        } else if (selectedType === 'slab') {
404→          dispatch({ type: 'SLAB_DELETE', floorId: activeFloorId });
405→        } else if (selectedType === 'sectionCut') {
406→          dispatch({ type: 'SECTION_DELETE', floorId: activeFloorId });
407→        } else if (selectedType === 'room') {
408→          dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
409→        }
410→        editorDispatch({ type: 'DESELECT' });
411→      }
412→    },
413→
414→    getCursor(toolState) {
415→      if (toolState.dragging) return 'grabbing';
416→      return 'default';
417→    },
418→  };
419→}
