42→export function createDoorPlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId }) {
43→  return {
44→    onMouseMove(modelPos, e, toolState) {
45→      const floor = getFloor(activeFloorId);
46→      if (!floor) return;
47→      const wall = findNearestWall(modelPos, floor.walls);
48→
49→      if (wall) {
50→        const offset = projectPointOnWall(wall, modelPos);
51→        const halfWidth = DOOR_WIDTH / 2;
52→        const maxOffset = wallLength(wall) - halfWidth;
53→        const clampedOffset = Math.max(halfWidth, Math.min(maxOffset, offset));
54→        const blocked = overlapsExisting(wall.id, clampedOffset, DOOR_WIDTH, floor.doors, floor.windows);
55→
56→        editorDispatch({
57→          type: 'UPDATE_TOOL_STATE',
58→          payload: {
59→            previewWallId: wall.id,
60→            previewOffset: clampedOffset,
61→            previewBlocked: blocked,
62→          },
63→        });
64→      } else {
65→        editorDispatch({
66→          type: 'UPDATE_TOOL_STATE',
67→          payload: { previewWallId: null, previewOffset: null, previewBlocked: false },
68→        });
69→      }
70→    },
71→
72→    onMouseDown(modelPos, e, toolState) {
73→      if (e.button !== 0) return;
74→      if (!toolState.previewWallId || toolState.previewBlocked) return;
75→
76→      const door = createDoor(toolState.previewWallId, toolState.previewOffset);
77→      dispatch({ type: 'DOOR_ADD', floorId: activeFloorId, door });
78→    },
79→
80→    onKeyDown(e, toolState) {
81→      if (e.key === 'Escape') {
82→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
83→      }
84→    },
85→
86→    getCursor(toolState) {
87→      if (!toolState.previewWallId || toolState.previewBlocked) return 'not-allowed';
88→      return 'copy';
89→    },
90→  };
91→}
