694→export default function PropertiesPanel() {
695→  const { project, dispatch } = useProject();
696→  const { selectedId, selectedType, activeFloorId, dispatch: editorDispatch } = useEditor();
697→  const floor = project.floors.find(f => f.id === activeFloorId);
698→  const u = useUnits();
699→
700→  const handleDelete = () => {
701→    if (!selectedId) return;
702→    if (selectedType === 'slab') {
703→      dispatch({ type: 'SLAB_DELETE', floorId: activeFloorId });
704→    } else if (selectedType === 'wall') {
705→      dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
706→    } else if (selectedType === 'beam') {
707→      dispatch({ type: 'BEAM_DELETE', floorId: activeFloorId, beamId: selectedId });
708→    } else if (selectedType === 'sectionCut') {
709→      dispatch({ type: 'SECTION_DELETE', floorId: activeFloorId });
710→    } else if (selectedType === 'annotation') {
711→      dispatch({ type: 'ANNOTATION_DELETE', floorId: activeFloorId, annotationId: selectedId });
712→    } else if (selectedType === 'stair') {
713→      dispatch({ type: 'STAIR_DELETE', floorId: activeFloorId, stairId: selectedId });
714→    } else if (selectedType === 'door') {
715→      dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
716→    } else if (selectedType === 'window') {
717→      dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
718→    } else if (selectedType === 'column') {
719→      dispatch({ type: 'COLUMN_DELETE', floorId: activeFloorId, columnId: selectedId });
720→    } else if (selectedType === 'room') {
721→      dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
722→    }
723→    editorDispatch({ type: 'DESELECT' });
724→  };
725→
726→  let content = <ProjectSummary project={project} floor={floor} dispatch={dispatch} />;
727→
728→  if (selectedId && floor) {
729→    if (selectedType === 'slab') {
730→      if (floor.slab?.id === selectedId) {
731→        content = <SlabProperties slab={floor.slab} floor={floor} dispatch={dispatch} floorId={activeFloorId} u={u} />;
732→      }
733→    } else if (selectedType === 'wall') {
734→      const wall = floor.walls.find(w => w.id === selectedId);
735→      if (wall) {
736→        content = <WallProperties wall={wall} dispatch={dispatch} floorId={activeFloorId} u={u} />;
737→      }
738→    } else if (selectedType === 'beam') {
739→      const beam = (floor.beams || []).find(b => b.id === selectedId);
740→      if (beam) {
741→        content = <BeamProperties beam={beam} floor={floor} dispatch={dispatch} floorId={activeFloorId} u={u} />;
742→      }
743→    } else if (selectedType === 'sectionCut') {
744→      const sectionCut = floor.sectionCut?.id === selectedId ? floor.sectionCut : null;
745→      if (sectionCut) {
746→        content = <SectionCutProperties sectionCut={sectionCut} dispatch={dispatch} floorId={activeFloorId} editorDispatch={editorDispatch} u={u} />;
747→      }
748→    } else if (selectedType === 'annotation') {
749→      const annotation = (floor.annotations || []).find((entry) => entry.id === selectedId);
750→      if (annotation) {
751→        content = <AnnotationProperties annotation={annotation} floor={floor} dispatch={dispatch} floorId={activeFloorId} u={u} />;
752→      }
753→    } else if (selectedType === 'stair') {
754→      const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
755→      if (stair) {
756→        content = <StairProperties stair={stair} project={project} dispatch={dispatch} floorId={activeFloorId} u={u} />;
757→      }
758→    } else if (selectedType === 'door') {
759→      const door = floor.doors.find(d => d.id === selectedId);
760→      const wall = door ? floor.walls.find(w => w.id === door.wallId) : null;
761→      if (door) {
762→        content = <DoorProperties door={door} wall={wall} dispatch={dispatch} floorId={activeFloorId} editorDispatch={editorDispatch} u={u} />;
763→      }
764→    } else if (selectedType === 'window') {
765→      const win = floor.windows.find(w => w.id === selectedId);
766→      const wall = win ? floor.walls.find(w => w.id === win.wallId) : null;
767→      if (win) {
768→        content = <WindowProperties window={win} wall={wall} dispatch={dispatch} floorId={activeFloorId} u={u} />;
769→      }
770→    } else if (selectedType === 'column') {
771→      const column = (floor.columns || []).find(c => c.id === selectedId);
772→      if (column) {
773→        content = <ColumnProperties column={column} floor={floor} dispatch={dispatch} floorId={activeFloorId} editorDispatch={editorDispatch} u={u} />;
774→      }
775→    } else if (selectedType === 'room') {
776→      const room = floor.rooms.find(r => r.id === selectedId);
777→      if (room) {
778→        content = <RoomProperties room={room} dispatch={dispatch} floorId={activeFloorId} />;
779→      }
780→    }
781→  }
782→
783→  return (
784→    <div className={styles.panel}>
785→      <div className={styles.unitToggle}>
786→        <span>Units:</span>
787→        <button
788→          className={`${styles.unitBtn} ${u.unit === 'mm' ? styles.unitBtnActive : ''}`}
789→          onClick={() => u.setUnit('mm')}
790→        >mm</button>
791→        <button
792→          className={`${styles.unitBtn} ${u.unit === 'm' ? styles.unitBtnActive : ''}`}
793→          onClick={() => u.setUnit('m')}
794→        >m</button>
795→      </div>
796→      {content}
797→      {selectedId && (
798→        <button className={styles.deleteBtn} onClick={handleDelete}>
799→          Delete {selectedType}
800→        </button>
801→      )}
802→    </div>
803→  );
804→}
