  1→import { createSlab } from '@/domain/models';
  2→import { SNAP_DISTANCE_PX } from '@/domain/defaults';
  3→import { distance } from '@/geometry/point';
  4→
  5→function resetSlabToolState(editorDispatch) {
  6→  editorDispatch({
  7→    type: 'UPDATE_TOOL_STATE',
  8→    payload: {
  9→      slabPoints: [],
 10→      slabPreviewPoint: null,
 11→    },
 12→  });
 13→}
 14→
 15→export function createSlabPlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport }) {
 16→  function commitSlab(points) {
 17→    const floor = getFloor(activeFloorId);
 18→    if (!floor || points.length < 3) return;
 19→
 20→    if (floor.slab) {
 21→      dispatch({
 22→        type: 'SLAB_UPDATE',
 23→        floorId: activeFloorId,
 24→        slab: {
 25→          id: floor.slab.id,
 26→          floorId: floor.id,
 27→          boundaryPoints: points,
 28→        },
 29→      });
 30→      editorDispatch({ type: 'SELECT_OBJECT', id: floor.slab.id, objectType: 'slab' });
 31→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Updated slab boundary.' });
 32→    } else {
 33→      const slab = createSlab(floor.id, points);
 34→      dispatch({ type: 'SLAB_SET', floorId: activeFloorId, slab });
 35→      editorDispatch({ type: 'SELECT_OBJECT', id: slab.id, objectType: 'slab' });
 36→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Created floor slab.' });
 37→    }
 38→
 39→    resetSlabToolState(editorDispatch);
 40→  }
 41→
 42→  return {
 43→    onMouseDown(modelPos, e, toolState) {
 44→      if (e.button !== 0) return;
 45→
 46→      const floor = getFloor(activeFloorId);
 47→      if (!floor) return;
 48→
 49→      const points = toolState.slabPoints || [];
 50→      const closeDistance = SNAP_DISTANCE_PX / viewport.zoom;
 51→
 52→      if (points.length === 0) {
 53→        if (floor.slab) {
 54→          editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw a new slab boundary to replace the current one.' });
 55→        }
 56→        editorDispatch({
 57→          type: 'UPDATE_TOOL_STATE',
 58→          payload: {
 59→            slabPoints: [{ x: modelPos.x, y: modelPos.y }],
 60→            slabPreviewPoint: { x: modelPos.x, y: modelPos.y },
 61→          },
 62→        });
 63→        return;
 64→      }
 65→
 66→      if (points.length >= 3 && distance(modelPos, points[0]) <= closeDistance) {
 67→        commitSlab(points);
 68→        return;
 69→      }
 70→
 71→      editorDispatch({
 72→        type: 'UPDATE_TOOL_STATE',
 73→        payload: {
 74→          slabPoints: [...points, { x: modelPos.x, y: modelPos.y }],
 75→          slabPreviewPoint: { x: modelPos.x, y: modelPos.y },
 76→        },
 77→      });
 78→    },
 79→
 80→    onMouseMove(modelPos, e, toolState) {
 81→      if (!(toolState.slabPoints || []).length) return;
 82→      editorDispatch({
 83→        type: 'UPDATE_TOOL_STATE',
 84→        payload: {
 85→          slabPreviewPoint: { x: modelPos.x, y: modelPos.y },
 86→        },
 87→      });
 88→    },
 89→
 90→    onDoubleClick(modelPos, e, toolState) {
 91→      const points = toolState.slabPoints || [];
 92→      if (points.length < 3) return;
 93→      commitSlab(points);
 94→    },
 95→
 96→    onKeyDown(e) {
 97→      if (e.key !== 'Escape') return;
 98→      resetSlabToolState(editorDispatch);
 99→      editorDispatch({ type: 'SET_TOOL', tool: 'select' });
100→    },
101→
102→    getCursor(toolState) {
103→      return (toolState.slabPoints || []).length ? 'crosshair' : 'crosshair';
104→    },
105→  };
106→}
