14→function rectPoints(element) {
15→  return [
16→    `${element.left},${-element.top}`,
17→    `${element.right},${-element.top}`,
18→    `${element.right},${-element.bottom}`,
19→    `${element.left},${-element.bottom}`,
20→  ].join(' ');
21→}
