41→        style={{ pointerEvents: 'none' }}
42→      >
43→        {scene.title}
44→      </text>
45→      {scene.elements.map((element) => {
46→        const style = STYLE_MAP[element.style] || STYLE_MAP.wall;
47→        return (
48→          <polygon
49→            key={element.id}
50→            points={rectPoints(element)}
51→            fill={style.fill}
52→            stroke={style.stroke}
53→            strokeWidth={1}
54→            vectorEffect="non-scaling-stroke"
55→          />
56→        );
57→      })}
58→      <line
