61→        x2={scene.bounds.maxX + 500}
62→        y2={-scene.groundLevel}
63→        stroke="var(--color-text-secondary)"
64→        strokeWidth={1}
65→        strokeDasharray="10 6"
66→        vectorEffect="non-scaling-stroke"
67→        opacity={0.6}
68→      />
69→      <BlueprintAnnotationLayer
70→        className="elevation-annotations"
71→        dimensions={annotationScene.dimensions}
72→      />
73→    </g>
74→  );
