60→function TagFigure({ tag }) {
61→  const lineHeight = 150;
62→  const startY = tag.position.y - ((tag.textLines.length - 1) * lineHeight) / 2;
63→
64→  return (
65→    <text
66→      key={tag.id}
67→      x={tag.position.x}
68→      y={startY}
69→      textAnchor={tag.textAnchor}
70→      dominantBaseline="middle"
71→      fill="var(--color-text-secondary)"
72→      fontSize={120}
